<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu-like Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
        }

        body {
            overflow: hidden;
            height: 100vh;
            width: 100vw;
            background-color: #2e3440;
            background-image: radial-gradient(#3b4252 1px, transparent 1px);
            background-size: 20px 20px;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100vw;
            height: 100vh;
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 48px;
            background-color: rgba(31, 35, 42, 0.9);
            backdrop-filter: blur(10px);
            display: flex;
            align-items: center;
            padding: 0 16px;
            border-top: 1px solid #4c566a;
            z-index: 1000;
        }

        .launcher {
            width: 32px;
            height: 32px;
            margin-right: 16px;
            background-color: #88c0d0;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .launcher:hover {
            transform: scale(1.1);
            background-color: #81c784;
        }

        .launcher-icon {
            width: 20px;
            height: 20px;
            fill: white;
        }

        /* Windows */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background-color: #3b4252;
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            overflow: hidden;
            display: flex;
            flex-direction: column;
        }

        .window-header {
            height: 32px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 12px;
            cursor: default;
            user-select: none;
        }

        .window-title {
            font-size: 13px;
            color: #d8dee9;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            flex-grow: 1;
        }

        .win-close {
            width: 12px;
            height: 12px;
            background-color: #bf616a;
            border-radius: 50%;
            cursor: pointer;
            margin-left: 8px;
            transition: all 0.2s ease;
        }

        .win-close:hover {
            transform: scale(1.1);
            background-color: #d32f2f;
        }

        .window-content {
            flex-grow: 1;
            overflow: auto;
            padding: 16px;
            color: #d8dee9;
        }

        /* Files App */
        #files-window {
            top: 50px;
            left: 100px;
            width: 480px;
            height: 320px;
        }

        .path-bar {
            display: flex;
            align-items: center;
            margin-bottom: 16px;
            padding: 8px;
            background-color: #4c566a;
            border-radius: 4px;
        }

        .path-segment {
            color: #88c0d0;
            cursor: pointer;
            font-size: 13px;
            margin-right: 8px;
        }

        .path-separator {
            color: #d8dee9;
            margin-right: 8px;
        }

        #files-up {
            width: 24px;
            height: 24px;
            background-color: #5e81ac;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            margin-right: 8px;
        }

        .fs-item {
            padding: 8px 12px;
            margin-bottom: 4px;
            background-color: #4c566a;
            border-radius: 4px;
            cursor: pointer;
            display: flex;
            align-items: center;
            transition: all 0.2s ease;
        }

        .fs-item:hover {
            background-color: #81c784;
            color: white;
        }

        .fs-icon {
            width: 20px;
            height: 20px;
            margin-right: 8px;
            fill: currentColor;
        }

        /* Notepad App */
        #notepad-window {
            top: 50px;
            left: 600px;
            width: 520px;
            height: 360px;
        }

        .tabs-container {
            display: flex;
            background-color: #4c566a;
            border-bottom: 1px solid #434c5e;
        }

        .tab {
            padding: 8px 16px;
            background-color: #3b4252;
            color: #d8dee9;
            cursor: pointer;
            font-size: 13px;
            border-top-left-radius: 4px;
            border-top-right-radius: 4px;
            margin-right: 4px;
            transition: all 0.2s ease;
        }

        .tab.active {
            background-color: #4c566a;
            color: #d8dee9;
            font-weight: bold;
        }

        .new-tab-btn {
            padding: 8px 12px;
            background-color: #3b4252;
            color: #d8dee9;
            cursor: pointer;
            border-top-left-radius: 4px;
            border-top-right-radius: 4px;
            margin-left: auto;
        }

        .new-tab-btn:hover {
            background-color: #81c784;
            color: white;
        }

        #editor {
            flex-grow: 1;
            width: 100%;
            height: 100%;
            background-color: #2e3440;
            color: #d8dee9;
            border: none;
            padding: 16px;
            font-family: monospace;
            font-size: 14px;
            resize: none;
            outline: none;
        }

        /* Icons */
        .folder-icon {
            fill: #fab387;
        }

        .file-icon {
            fill: #d8dee9;
        }

        .back-icon {
            width: 16px;
            height: 16px;
            stroke: white;
            stroke-width: 2;
            fill: none;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div id="open-files" class="launcher" title="Files">
                <svg class="launcher-icon" viewBox="0 0 24 24">
                    <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
                </svg>
            </div>
            <div id="open-notepad" class="launcher" title="Notepad">
                <svg class="launcher-icon" viewBox="0 0 24 24">
                    <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>
                </svg>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window">
            <div class="window-header">
                <span class="window-title">Files</span>
                <div class="win-close"></div>
            </div>
            <div class="window-content">
                <div class="path-bar">
                    <div id="files-up">
                        <svg class="back-icon" viewBox="0 0 24 24">
                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
                        </svg>
                    </div>
                    <span id="files-path">/</span>
                </div>
                <div id="files-list"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window">
            <div class="window-header">
                <span class="window-title">Notepad</span>
                <div class="win-close"></div>
            </div>
            <div class="tabs-container">
                <div id="tabs"></div>
                <div id="new-tab" class="new-tab-btn">+ New Tab</div>
            </div>
            <textarea id="editor" placeholder="Type here..."></textarea>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            "/": ["bin", "etc", "home", "usr", "var"],
            "/bin": ["bash", "ls", "cat", "grep"],
            "/etc": ["passwd", "hosts", "network.conf"],
            "/home": ["user"],
            "/home/user": ["Documents", "Downloads", "Pictures", "notes.txt"],
            "/home/user/Documents": ["report.odt", "resume.pdf"],
            "/home/user/Downloads": ["ubuntu.iso", "updates.tar.gz"],
            "/home/user/Pictures": ["wallpaper.png", "screenshot.jpg"],
            "/usr": ["bin", "lib", "share"],
            "/var": ["log", "www", "cache"]
        };

        // Files App Logic
        const filesWindow = document.getElementById('files-window');
        const filesPath = document.getElementById('files-path');
        const filesList = document.getElementById('files-list');
        const filesUp = document.getElementById('files-up');

        let currentFilesPath = "/";

        function renderFiles() {
            filesPath.textContent = currentFilesPath;
            filesList.innerHTML = '';

            // Add up button if not at root
            if (currentFilesPath !== '/') {
                const upItem = document.createElement('div');
                upItem.className = 'fs-item';
                upItem.innerHTML = `
                    <svg class="fs-icon back-icon" viewBox="0 0 24 24">
                        <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
                    </svg>
                    ..
                `;
                upItem.addEventListener('click', function() {
                    const parts = currentFilesPath.split('/').filter(p => p);
                    if (parts.length > 0) {
                        parts.pop();
                        currentFilesPath = '/' + parts.join('/');
                        renderFiles();
                    }
                });
                filesList.appendChild(upItem);
            }

            // Get files in current directory
            const files = fileSystem[currentFilesPath] || [];

            // Separate folders and files, sort alphabetically
            const folders = [];
            const filesOnly = [];

            files.forEach(name => {
                if (fileSystem['/' + name]) {
                    folders.push(name);
                } else {
                    filesOnly.push(name);
                }
            });

            const sortedFiles = [...folders.sort(), ...filesOnly.sort()];

            // Render each file/folder
            sortedFiles.forEach(name => {
                const item = document.createElement('div');
                item.className = 'fs-item';

                // Check if it's a folder (has children in the filesystem)
                const isFolder = !!fileSystem[currentFilesPath === '/' ? '/' + name : currentFilesPath + '/' + name];

                if (isFolder) {
                    item.innerHTML = `
                        <svg class="fs-icon folder-icon" viewBox="0 0 24 24">
                            <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
                        </svg>
                        ${name}
                    `;
                } else {
                    item.innerHTML = `
                        <svg class="fs-icon file-icon" viewBox="0 0 24 24">
                            <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>
                        </svg>
                        ${name}
                    `;
                }

                item.addEventListener('dblclick', function() {
                    if (isFolder) {
                        currentFilesPath = currentFilesPath === '/' ? '/' + name : currentFilesPath + '/' + name;
                        renderFiles();
                    } else {
                        // For files, just show an alert
                        alert(`Opening file: ${name}\n(This is a demo - file content would open here in a real app)`);
                    }
                });

                filesList.appendChild(item);
            });
        }

        // Initialize Files App
        renderFiles();

        // Notepad App Logic
        const notepadWindow = document.getElementById('notepad-window');
        const tabsContainer = document.getElementById('tabs');
        const newTabBtn = document.getElementById('new-tab');
        const editor = document.getElementById('editor');

        let tabs = [];
        let activeTabId = null;

        function loadTabs() {
            try {
                const savedTabs = localStorage.getItem('ubuntu_notepad_tabs');
                if (savedTabs) {
                    tabs = JSON.parse(savedTabs);
                    if (tabs.length > 0) {
                        activeTabId = tabs[0].id;
                        renderTabs();
                        editor.value = tabs.find(t => t.id === activeTabId).content;
                    }
                } else {
                    // Create initial empty tab
                    createTab();
                }
            } catch (e) {
                console.error('Error loading tabs:', e);
                createTab();
            }
        }

        function saveTabs() {
            try {
                localStorage.setItem('ubuntu_notepad_tabs', JSON.stringify(tabs));
            } catch (e) {
                console.error('Error saving tabs:', e);
            }
        }

        function generateId() {
            return 'tab-' + Date.now() + '-' + Math.floor(Math.random() * 1000);
        }

        function createTab() {
            const id = generateId();
            tabs.push({ id, title: `Tab ${tabs.length + 1}`, content: '' });
            activeTabId = id;
            renderTabs();
            editor.value = '';
            saveTabs();
        }

        function renderTabs() {
            tabsContainer.innerHTML = '';

            tabs.forEach(tab => {
                const tabElement = document.createElement('div');
                tabElement.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabElement.textContent = tab.title;

                tabElement.addEventListener('click', function() {
                    activeTabId = tab.id;
                    renderTabs();
                    editor.value = tabs.find(t => t.id === activeTabId).content;
                });

                tabsContainer.appendChild(tabElement);
            });
        }

        // Event Listeners for Notepad
        newTabBtn.addEventListener('click', createTab);

        editor.addEventListener('input', function() {
            const tab = tabs.find(t => t.id === activeTabId);
            if (tab) {
                tab.content = editor.value;
                saveTabs();
            }
        });

        // Initialize Notepad
        loadTabs();

        // Window Management Logic
        function toggleWindow(windowId, launcherId) {
            const windowElement = document.getElementById(windowId);

            if (windowElement.style.display === 'none') {
                windowElement.style.display = 'flex';
            } else {
                windowElement.style.display = 'none';
            }
        }

        // Files Launcher
        document.getElementById('open-files').addEventListener('click', function() {
            const filesWindow = document.getElementById('files-window');
            if (filesWindow.style.display === 'none') {
                filesWindow.style.display = 'flex';
            } else {
                filesWindow.style.display = 'none';
            }
        });

        // Notepad Launcher
        document.getElementById('open-notepad').addEventListener('click', function() {
            const notepadWindow = document.getElementById('notepad-window');
            if (notepadWindow.style.display === 'none') {
                notepadWindow.style.display = 'flex';
            } else {
                notepadWindow.style.display = 'none';
            }
        });

        // Close buttons
        document.querySelectorAll('.win-close').forEach(closeBtn => {
            closeBtn.addEventListener('click', function() {
                this.closest('.window').style.display = 'none';
            });
        });

        // Initialize windows state
        filesWindow.style.display = 'flex';
        notepadWindow.style.display = 'flex';

        // Make windows draggable (basic implementation)
        document.querySelectorAll('.window-header').forEach(header => {
            header.addEventListener('mousedown', function(e) {
                const windowElement = this.closest('.window');

                // Get initial positions
                let offsetX = e.clientX - windowElement.getBoundingClientRect().left;
                let offsetY = e.clientY - windowElement.getBoundingClientRect().top;

                function moveWindow(event) {
                    windowElement.style.left = (event.clientX - offsetX) + 'px';
                    windowElement.style.top = (event.clientY - offsetY) + 'px';
                }

                function stopMoving() {
                    document.removeEventListener('mousemove', moveWindow);
                    document.removeEventListener('mouseup', stopMoving);
                }

                document.addEventListener('mousemove', moveWindow);
                document.addEventListener('mouseup', stopMoving);
            });
        });
    </script>
</body>
</html>
